// Script Continued Below
var ClientUserInfoScripts = Class.create();
ClientUserInfoScripts.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {

	getUserDefaultOU : function(userId)
	{
		if (!userId || userId == '')
			userId = gs.getUserID();
		var defaultOU = '';
		var grOM = new GlideRecordSecure('x_153465_discovert_discover_office_members');
		grOM.addQuery('office_member', userId);
		grOM.setLimit(1);
		grOM.query();
		if (grOM.next()){
			defaultOU = grOM.getValue("u_default_ou");
		}
		// STRY0104389 
		return defaultOU + '';
	},

	IsUserGlobalTA: function()
	{
		var userId = this.getParameter('UserId');
		var ou = this.getParameter('OU');
		return new UserInfoScripts().IsUserTaskingAuthority(userId, ou);
	},

	IsUserInOU: function()
	{
		//Query organizational unit members to see if the user is a member
		var userID = this.getParameter('UserId');
		var ouID = this.getParameter('OU');

		var UserPermissions = new UserInfoScripts();	
		if(UserPermissions.IsUserInOU(ouID,userID)){
			return true;
		}
		else{
			return false;
		}
	},

	//  RAJ STSK0011104 - allow changing task assingment based on user being a tasking authority 
	//  changed the script include to add a method to determine if the user is a Tasking Authority
	IsUserTaskingAuthority: function()
	{
		//Query organizational unit members to see if the user is a Tasking Authority for the OU
		var userID = this.getParameter('UserId');
		var ouID = this.getParameter('OU');
		//  RAJ STSK0011104 updated to control whether a user can assign tasks based on Tasking Authority instead of ownership of the task or membership in the OU

		var UserPermissions  = new UserInfoScripts();
		if(UserPermissions.IsUserTaskingAuthority(ouID,userID).toString() == 'true'){
			return true;
		}
		else{
			return false;
		}
	},

	//  RAJ STSK0011104 if the user is NOT a TA, but is in the OU, they can assign themselves to the Tasker, so the user needs to be able to see the "assigned members.  
//  RAJ STSK0011104 - allow changing task assingment based on user being a tasking authority 
	//  changed the script include to add a method to determine if the user is a Tasking Authority
	CanUserAssignSelfOrOthers: function()
	{
		//Query organizational unit members to see if the user is a Tasking Authority for the OU
		var userID = this.getParameter('UserId');
		var ouID = this.getParameter('OU');
		//  RAJ STSK0011104 updated to control whether a user can assign tasks based on Tasking Authority instead of ownership of the task or membership in the OU
		var UserPermissions  = new UserInfoScripts();
		if(UserPermissions.CanUserAssignSelfOrOthers(ouID,userID)){
			return true;
		}
		else{
			return false;
		}
	},
	// STRY0067125 - Check the users permissions for assigning members in a template
	CanUserAssignSelfOrOthersInTemplate: function()
	{
		//Query organizational unit members to see if the user is a Tasking Authority for the OU
		var userID = this.getParameter('UserId');
		var ouID = this.getParameter('OU');
		var template = this.getParameter('Template');
		//  RAJ STSK0011104 updated to control whether a user can assign tasks based on Tasking Authority instead of ownership of the task or membership in the OU
		var UserPermissions  = new UserInfoScripts();
		if(UserPermissions.CanUserAssignSelfOrOthersInTemplate(ouID,userID, template)){
			return true;
		}
		else{
			return false;
		}
	},

	IsUserOUTA: function(){

		var userId = this.getParameter('UserId');
		var ou = this.getParameter('OU');
		var answer = "false";
		var grMembers = new GlideRecordSecure('x_153465_discovert_discover_office_members');
		grMembers.addQuery('discover_office_hierarchy', ou);
		grMembers.addQuery('office_member' , userId);
		grMembers.addQuery('office_task_authority', 'true');	
		grMembers.query();


		if(grMembers.next()){
			return true;
		}else{
			return false;
		}


	},
	isOUExternalTA: function(){
		var strOU = this.getParameter('OU');
		var grOU = new GlideRecordSecure("x_153465_discovert_discover_office_hierarchy");
		grOU.addQuery('sys_id',strOU);
		grOU.addQuery('u_external_flag', true);
		grOU.query();
		if(grOU.next()){
			return true;
		}

		return  false;
	},
	userHasRole: function()
	{
		var user = this.getParameter('user');
		var roles = this.getParameter("roles");
		var hasRole = false;
		var parsRoles = roles.split(",");
		var permissions = [];
		for(var i=0; i<parsRoles.length; i++){
			var grRole = new GlideRecord('sys_user_has_role');
			grRole.addQuery('user', user);
			grRole.addQuery('role.name', parsRoles[i]);
			grRole.query();
			if (grRole.next()) {
				permissions.push({
					"role":parsRoles[i], "hasRole": true
				});
			}else{
				permissions.push({
					"role":parsRoles[i], "hasRole": false
				});
			}
		}
		var data = JSON.stringify(permissions);
		return data;
	},
	type: 'ClientUserInfoScripts'
});
